#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node* next;
} Node;

int getMiddleElement(Node* head) {
    Node* slow = head;
    Node* fast = head;
    while (fast != NULL && fast->next != NULL) {
        slow = slow->next;
        fast = fast->next->next;
    }
    return slow->val;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node *head = NULL, *tail = NULL;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            Node* nd = (Node*)malloc(sizeof(Node));
            nd->val = x; nd->next = NULL;
            if (!head) head = tail = nd; else { tail->next = nd; tail = nd; }
        }
        printf("%d\n", getMiddleElement(head));
        while (head) { Node* tmp = head; head = head->next; free(tmp); }
    }
    return 0;
}

