#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* next;
    Node(int v) : val(v), next(nullptr) {}
};

int getMiddleElement(Node* head) {
    Node* slow = head;
    Node* fast = head;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
    }
    return slow->val;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        Node *head = nullptr, *tail = nullptr;
        for (int i = 0; i < N; ++i) {
            int x; cin >> x;
            Node* nd = new Node(x);
            if (!head) head = tail = nd; else { tail->next = nd; tail = nd; }
        }
        cout << getMiddleElement(head) << '\n';
        while (head) { Node* tmp = head; head = head->next; delete tmp; }
    }
    return 0;
}

